('old-data-berta2-all-20260501-01', '87c31917', 'Berta 2.0', U&'{"id":"87c31917","Nom commercial":"Grand Natte","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Saint-Philippe","Adresse":"111 Chemin de Ceinture, 97442 Saint-Philippe - Mare-Longue","Site web":"","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"Maison","Localisations":"Milieu rural","Code postal":"97442","Bureau postal":"Saint-Philippe","Lieux-dits":"Mare-Longue","Prestations sur place":"dressing , barbecue , vue montagne , grand espace , vue mer , linge de maison , parking , ventilateur , salon , chauffage , jardin , TV , micro-ondes , linge de toilette , douche , Cafeti\00E8re , frigo , cuisine \00E9quip\00E9e , salon de jardin , jardin arbor\00E9 , acc\00E8s internet , plaque de cuisson , grille-pain , jardin cl\00F4tur\00E9 , lave-linge , cuisine ext\00E9rieure , netflix","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,point de vue panoramique,for\00EAt,sites touristiques","Mode de paiement":"Esp\00E8ces,airbnb","Langues":"fran\00E7ais,cr\00E9ole","Fixe":"","Mobile":"0692 25 07 52","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"stephen.reviron@orange.fr","Capacit\00E9":"4","Classement":"","Accroche":"Venez d\00E9couvrir Grand natte, nich\00E9 en lisi\00E8re de la for\00EAt de Mare Longue avec vue sur la mer, au c\0153ur d''un jardin tropical plant\00E9 d''aromatiques et d''arbres fruitiers.","Descriptif":"L''\00E9colodge se situe \00E0 quelques minutes seulement de Baril les bains (avec sa piscine, son bassin naturel, son aire de pique nique avec kiosques).\\nLes amateurs de balades, de randonn\00E9es  et de cyclisme seront \00E0 une centaine de m\00E8tres seulement des sentiers forestiers et les caps de Saint Philippe offrent de nombreux spots de p\00EAche pour les passionn\00E9s.\\nPour les moments farniente, vous disposez de terrasses pour l''ap\00E9ro ou pour profiter du soleil, du chant des oiseaux et de la vue sur la nature environnante. \\nAvec son salon spacieux et ses deux cuisines, vous pourrez partager de bons moments conviviaux en famille ou entre amis, autour d''un cari au feu de bois ou des jeux de soci\00E9t\00E9 (mis \00E0 disposition).\\nCe logement ind\00E9pendant, dispose d''une place de parking, d''une chambre avec lit double, d''un canap\00E9-lit de 2 places dans le salon, d''une cuisine \00E9quip\00E9e, de terrasses, d''une smart TV avec Netflix gratuit, wifi, brasseurs d''air  et ventilateurs...\\nL''\00E9colodge est quasi autonome en \00E9lectricit\00E9 gr\00E2ce \00E0 sa centrale solaire par cons\00E9quent, pas de four \00E9lectrique ni d''\00E9quipement trop \00E9nergivore.\\n\\nPossibilit\00E9 de jumeler avec Ti Natte pour accueillir jusqu''\00E0 8 personnes.\\nVenez vous ressourcez...","Descriptif du plan d''acc\00E8s":"Sur la N2 prendre \00E0 gauche au chemin ceinture ou route foresti\00E8re Mare Longue continuer tout droit sur chemin ceinture. Ti Natte se trouve sur votre gauche au 111 chemin Ceinture.","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"11/8/2023","Date de fermeture":"","Fournisseur - Nom":"Mr Stephen REVIRON","Fournisseur - SIRET":"42323574500085","Fournisseur - adresse":"Mr Stephen REVIRON: 111 chemin de ceinture, 97442 Saint-Philippe","Fournisseur - contacts":"stephen.reviron@orange.fr / 0692250752","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.357511, 55.747532","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC585HTR","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'HLO', 'Grand Natte', '87c31917', NULL, 'RUN', 'draft', 'active', U&'{"legacy_object_id":"87c31917","source_category":"Location saisonni\00E8re","source_subcategory":"Maison","source_group_category":"H\00E9bergement","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
('old-data-berta2-all-20260501-01', '430daa4e', 'Berta 2.0', U&'{"id":"430daa4e","Nom commercial":"LA VILLA ROSANNA - Bleu Azur","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Le Tampon","Adresse":"8 E Pascal BLAISE, 97430 Le Tampon - Trois Mares","Site web":"https://www.lavillarosanna.fr/","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"G\00EEte & Villa","Localisations":"","Code postal":"97430","Bureau postal":"Le Tampon","Lieux-dits":"Trois Mares","Prestations sur place":"barbecue , fer et planche \00E0 repasser , vue montagne , sur r\00E9servation , grand espace , vue mer , linge de maison , parking , TV satellite , salon , wifi gratuit , lave vaisselle , lave linge privatif , micro-ondes , linge de toilette , douche , four , Cafeti\00E8re , frigo , kitchenette \00E9quip\00E9e , sanitaires priv\00E9s , terrasse , cuisine , salle \00E0 manger , salle de bain priv\00E9e , salon de jardin , espace de restauration en ext\00E9rieur , acc\00E8s internet , serviettes. , cour cl\00F4tur\00E9e , plaque de cuisson , s\00E8che-cheveux , piscine commune , bouilloire , grille-pain","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,commerce alimentaire,point de vue panoramique,sites touristiques,arr\00EAt bus,poste - boite aux lettres,transports en commun,station service,pharmacie,boulangerie,banque - guichet automatique,Point chaud,stade de foot,m\00E9decin,tabac presse,coiffeur,centre commercial,commerces,Centre - Ville,p\00E2tisserie,Gare routi\00E8re,piscine,restaurants,piscine municipale,centre m\00E9dical,h\00E9bergements,\00E9picerie,Terrain de jeux pour enfants,aire de jeux,centre de bien-\00EAtre,Toutes commodit\00E9s,snack,parcours de sant\00E9","Mode de paiement":"Virement,Esp\00E8ces","Langues":"fran\00E7ais,anglais","Fixe":"","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"larosa.therese@gmail.com","Capacit\00E9":"2","Classement":"","Accroche":"Situ\00E9e \00E0 mi chemin entre mer et montagne, LA VILLA ROSANNA est \00E0 Trois Mares, un quartier du Tampon avec un climat doux et tr\00E8s agr\00E9able. C''est un lieu calme propice au repos pour se ressourcer. Loin du stress du quotidien, LA VILLA ROSANNA est une invitation \00E0 une pause pour un moment intime \00E0 deux. Nous vous proposons trois appartements confortables, ind\00E9pendantes et spacieuses : La R\00E9unionnaise, L''Oc\00E9an et Bleu Azur.","Descriptif":"Le site vous fait profiter d''une vue plongeante sur la mer  et d''un magnifique coucher du soleil \00E0 admirer en amoureux, endroit paisible pour se d\00E9tendre sur la plage de la piscine chauff\00E9e et prendre un verre sur votre terrasse ou balcon.\\nL''\00E9tablissement se trouve proche de nombreux sites attractifs comme le sentier de Dassy, le bord de mer de Saint pierre avec sa plage, des parcours de sant\00E9, le Parc des Palmiers, pleins de lieux improbables,\2026 et puis La plaine des Cafres qui donne acc\00E8s au site du volcan et \00E0 de nombreux sentiers de randonn\00E9es et de promenades. \\n\\nEn outre, les infrastructures, supermarch\00E9s, m\00E9decins, h\00F4tels, restaurants, bars,\2026 sont \00E0 proximit\00E9.","Descriptif du plan d''acc\00E8s":"Depuis l''a\00E9roport Roland Garros :\\nItin\00E9raire par les bas :\\nSortir de l''a\00E9roport et prendre la direction de Saint-Denis.\\nEnsuite, vous sortez de Saint-Denis en empruntant la route du littoral. \\nPrendre la direction de Saint-Pierre. Ensuite, prendre la direction Le Tampon (RN3), environ 10 km.\\nPrendre la direction de Trois-Mares, vous continuerez \00E0 rouler sur la D3 jusqu''\00E0 arriv\00E9e \00E0 la mairie de Trois-Mares. Au rond-point, prendre le chemin St\00E9phane situ\00E9 \00E0 gauche. Vous continuez \00E0 descendre le chemin et vous trouverez la rue BLAISE Pascal sur votre gauche. LA VILLA ROSANNA se situe \00E0 l''entr\00E9e de la rue, tout de suite \00E0 gauche.","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"21/6/2022","Date de fermeture":"","Fournisseur - Nom":"","Fournisseur - SIRET":"83814000200018","Fournisseur - adresse":"","Fournisseur - contacts":"","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.267713, 55.497769","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC500HT@","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'HLO', 'LA VILLA ROSANNA - Bleu Azur', '430daa4e', NULL, 'RUN', 'published', 'active', U&'{"legacy_object_id":"430daa4e","source_category":"Location saisonni\00E8re","source_subcategory":"G\00EEte & Villa","source_group_category":"H\00E9bergement","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
('old-data-berta2-all-20260501-01', '83237123', 'Berta 2.0', U&'{"id":"83237123","Nom commercial":"Ti Natte","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Saint-Philippe","Adresse":"111 chemin de ceinture, 97442 Saint-Philippe - Mare-Longue","Site web":"https://ti-natte.business.site/","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"Bungalow & Chalet","Localisations":"Parc National de la R\00E9union","Code postal":"97442","Bureau postal":"Saint-Philippe","Lieux-dits":"Mare-Longue","Prestations sur place":"barbecue , climatisation , jacuzzi , vue mer , linge de maison , parking , salon , jardin , micro-ondes , wifi , douche , four , terrasse , salon de jardin , linge de toilette , cuisine , jardin arbor\00E9 , serviettes. , veranda couverte , Cafeti\00E8re , frigo , parking s\00E9curis\00E9 , SPA","Prestations \00E0 proximit\00E9":"tunnels de lave,littoral,site - lieu culturel,for\00EAt,jardin,p\00EAche,restaurants,sentiers de randonn\00E9es,commerces,sites - lieux culturels,sites touristiques,route du volcan","Mode de paiement":"Virement,Esp\00E8ces,airbnb","Langues":"fran\00E7ais","Fixe":"","Mobile":"0692250752","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"stephen.reviron@orange.fr","Capacit\00E9":"3","Classement":"3 Etoile(s)","Accroche":"Ti Natte est un petit chalet ind\00E9pendant de 31m\00B2 situ\00E9 \00E0 quelques pas seulement des premiers sentiers forestiers de la for\00EAt de Mare Longue \00E0 Saint Philippe.","Descriptif":"Id\00E9al pour les couples amoureux de la nature, ce lodge meubl\00E9 se compose comme suit : Une pi\00E8ce \00E0 vivre compos\00E9e d''une cuisine \00E9quip\00E9e (caf\00E9 et th\00E9 \00E0 dispo), d''un coin salon avec canap\00E9-lit 2 personnes, TV, Wifi et climatisation, donnant sur une varangue munie d''un Spa 2 places haut de gamme pour vous relaxer. Une chambre climatis\00E9e avec un lit de 160x200 et dressing. Une salle d''eau \00E9quip\00E9e d''une grande douche 180x90, d''un lavabo et de toilettes avec douchette. A l\2019ext\00E9rieur, une terrasse ombrag\00E9e dot\00E9e d''un salon de jardin propice \00E0 la d\00E9tente et d''un barbecue pour profiter de grillades en plein air. La cour accueille une place de stationnement priv\00E9e et s\00E9curis\00E9e ainsi qu''un jardin d''ornement.\\nArriv\00E9e 15h00 - D\00E9part 11h00","Descriptif du plan d''acc\00E8s":"Sur la N2 prendre \00E0 gauche au chemin ceinture ou route foresti\00E8re Mare Longue continuer tout droit sur chemin ceinture. Ti Natte se trouve sur votre gauche au 111 chemin Ceinture.","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"16/7/2021","Date de fermeture":"","Fournisseur - Nom":"Mr Stephen REVIRON","Fournisseur - SIRET":"43223574500085","Fournisseur - adresse":"Mr Stephen REVIRON: 111 chemin de ceinture, 97442 Saint-Philippe","Fournisseur - contacts":"stephen.reviron@orange.fr / 0692250752","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.357721520408163, 55.74748422924956","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC443HT@","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"AD2R","source_system":"berta_v2_csv_export"}', 'HLO', 'Ti Natte', '83237123', NULL, 'RUN', 'published', 'active', U&'{"legacy_object_id":"83237123","source_category":"Location saisonni\00E8re","source_subcategory":"Bungalow & Chalet","source_group_category":"H\00E9bergement","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
