('old-data-berta2-all-20260501-01', 'recD5BtUZul1AMUmq', 'Berta 2.0', U&'{"id":"recD5BtUZul1AMUmq","Nom commercial":"Le Gecko Vert ","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"9  Impasse des Pipengayes, 97480 Saint-Joseph - Manapany-Les-Bains","Site web":"https://lamaisondeshotes.re/le-gecko-vert-manapany-les-bains/","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"Appartement","Localisations":"Village","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"Manapany-Les-Bains","Prestations sur place":"climatisation , fer et planche \00E0 repasser , lave linge privatif , lave vaisselle , linge de maison , parking , piscine , TV satellite , ventilateur , wifi , coffre-fort","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,riviere,commerce alimentaire,sites touristiques,Bassin de Manapany,sites - lieux culturels,Restauration","Mode de paiement":"Virement,Esp\00E8ces,booking,airbnb","Langues":"fran\00E7ais,cr\00E9ole,anglais","Fixe":"","Mobile":"0692 64 69 96","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"lamaisondeshotes974@gmail.com","Capacit\00E9":"6","Classement":"2 Etoile(s)","Accroche":"Situ\00E9 au coeur de Manapany les Bains, Le Gecko Vert propose un appartement enti\00E8rement meubl\00E9 pouvant accueillir 6 personnes.","Descriptif":"L''appartement \00E9quip\00E9 de 2 chambres avec canap\00E9 lits. Enti\00E8rement r\00E9nov\00E9 et tout \00E9quip\00E9, il est situ\00E9 au rez-de-chauss\00E9e en face d''une grande piscine. \\n\\nLe Gecko Vert se trouve \00E0 8 minutes \00E0 pied du bassin de baignade, a une vue sur mer et montagne dans un endroit particuli\00E8rement calme.\\n\\nLa location se fait \00E0 partir de 4 nuits minimum. D\00E9pose bagages disponible","Descriptif du plan d''acc\00E8s":"Venant de l''ouest, traverser la ville de Saint-Pierre puis prendre la direction de Grand Bois. Arriv\00E9 \00E0 Manapany les Bains, prendre la premi\00E8re route \00E0 droite puis encore la premi\00E8re \00E0 droite. \\nLa r\00E9sidence est recouverte d''un toit en bois.\\nVenant de l''est, prendre la sortie Saint-Jospeh en direction de Saint-Pierre. Arriv\00E9 \00E0 Manapany les Bains (juste apr\00E8s un grand rond point), tourner \00E0 gauche au premier carrefour puis \00E0 droite. La r\00E9sidence est \00E0 100m, recouverte d''un toit en bois. ","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"","Date de fermeture":"","Fournisseur - Nom":"Mr Denis et Francia Heuvrard","Fournisseur - SIRET":"85409099000029","Fournisseur - adresse":"Mr Denis et Francia Heuvrard: 9 Impasse des Pipengayes, 97480 Saint-Joseph - Manapany-Les-Bains","Fournisseur - contacts":"lamaisondeshotes974@gmail.com / 0692 64 69 96","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.373684, 55.594180","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC310HT@","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'HLO', 'Le Gecko Vert', 'recD5BtUZul1AMUmq', NULL, 'RUN', 'published', 'active', U&'{"legacy_object_id":"recD5BtUZul1AMUmq","source_category":"Location saisonni\00E8re","source_subcategory":"Appartement","source_group_category":"H\00E9bergement","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
('old-data-berta2-all-20260501-01', 'recDHjG1lQVPlasLV', 'Berta 2.0', U&'{"id":"recDHjG1lQVPlasLV","Nom commercial":"La Maison des H\00F4tes ","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"7  Rue Joseph de Souville, 97480 Saint-Joseph - centre ville","Site web":"https://lamaisondeshotes.re/la-maison-des-hotes-saint-joseph/","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Chambre d''h\00F4tes","Nom sous cat\00E9gorie":"Chambre d''h\00F4te","Localisations":"Milieu rural","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"centre ville","Prestations sur place":"climatisation , fer et planche \00E0 repasser , jardin , lave linge privatif , linge de maison , parking , piscine , s\00E8che linge privatif , TV satellite , ventilateur , wifi , coffre-fort","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,banque - guichet automatique,commerce alimentaire,riviere","Mode de paiement":"Virement,Esp\00E8ces,booking,airbnb","Langues":"fran\00E7ais,anglais","Fixe":"","Mobile":"0692 64 69 96","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"lamaisondeshotes974@gmail.com","Capacit\00E9":"6","Classement":"","Accroche":"Situ\00E9e au centre ville historique de Saint-Joseph, accessible facilement, dans un environnement calme et silencieux, La Maison des H\00F4tes, peut accueillir 6 personnes dans une ambiance conviviale, agr\00E9able.","Descriptif":"La grande villa propose 3 chambres spacieuses dont une avec un lit king size. \\nPas de TV dans les chambres, pour \00E9viter le bruit, mais un salon TV.\\nClim dans toutes les chambres\\nLumineuses\\n\\nElle dispose \00E9galement d''une grande  terrasse, d''une cuisine ext\00E9rieure et d''une piscine sans vis \00E0 vis, un salon cr\00E9ole typique d''ext\00E9rieur,  de nombreuses biblioth\00E8ques dans la maison...\\n\\nDe nombreux restaurants se trouvent \00E0 proximit\00E9 proposant des plats \00E0 emporter. Manapany et son bassin de baignade se situent \00E0 3 km et la rivi\00E8re Langevin est \00E0  7 km, le Piton Babet \00E0 environ 200m ! \\n\\nTarif affich\00E9 : 3 nuits minimum.","Descriptif du plan d''acc\00E8s":"Venant de l''ouest, franchir le pont de la rivi\00E8re des Remparts puis tourner \00E0 droite. Se diriger vers le centre ville en restant sur l''axe principal. La rue Joseph de Souville est \00E0 sens unique en montant. Il y a une agence de la BRED qui se situe \00E0 son intersection. La villa munie d''un portail blanc et d''un mur de cl\00F4ture en pierre taill\00E9e est en haut \00E0 gauche.\\nVenant de l''est, suivre la direction de Saint-Pierre. Arriv\00E9 au pont de la rivi\00E8re des Remparts, tourner \00E0 gauche en direction du centre ville. Rester sur l''axe principal. Tourner de nouveau \00E0 gauche devant l''agence de la BRED. La villa munie d''un portail blanc et d''un mur de cl\00F4ture en pierre taill\00E9e est en haut \00E0 gauche.","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"","Date de fermeture":"","Fournisseur - Nom":"Mr Denis et Francia Heuvrard","Fournisseur - SIRET":"85409099000029","Fournisseur - adresse":"Mr Denis et Francia Heuvrard: 9 Impasse des Pipengayes, 97480 Saint-Joseph - Manapany-Les-Bains","Fournisseur - contacts":"lamaisondeshotes974@gmail.com / 0692 64 69 96","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.378030, 55.618277","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC309HT@","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'HLO', U&'La Maison des H\00F4tes', 'recDHjG1lQVPlasLV', NULL, 'RUN