('old-data-berta2-all-20260501-01', '91debdd2', 'Berta 2.0', U&'{"id":"91debdd2","Nom commercial":"La Case \00E0 Nona","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"127 Boulevard de l''Oc\00E9an, 97480 Saint-Joseph - Manapany-Les-Bains","Site web":"","Groupe cat\00E9gorie":"Restauration","Nom cat\00E9gorie":"Restaurant","Nom sous cat\00E9gorie":"Restaurant","Localisations":"Littoral","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"Manapany-Les-Bains","Prestations sur place":"parking public , vue mer , terrasse , bar","Prestations \00E0 proximit\00E9":"point de vue panoramique,sites touristiques,Bassin de Manapany,arr\00EAt bus,sites - lieux culturels,restaurants,h\00E9bergements","Mode de paiement":"Esp\00E8ces,Carte Bancaire","Langues":"neerlandais,fran\00E7ais,cr\00E9ole,anglais,italien","Fixe":"","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"lacaseanona@gmail.com","Capacit\00E9":"38","Classement":"","Accroche":"Cuisine bistronomique fran\00E7aise et sicilienne.","Descriptif":"Situ\00E9 \00E0 Manapany les bains \00E0 deux pas du bassin nous vous proposons une cuisine bistronomique fran\00E7aise et sicilienne. \\nNous vous accueillons du mardi au samedi de 7h30 \00E0 22h avec un service continu, du petit-d\00E9jeuner \+01F373 jusqu\2019au d\00EEner \+01F37D en passant par l\2019aperitivo \+01F942\\nTout nos produits son frais, locaux et confectionn\00E9s sur place. \\nEn clair tout est fait maison.\\nLa carte n''est pas fixe, le chef travaille avec des produits de saison.\\nLe restaurant propose des plats v\00E9g\00E9tariens et vegans.\\nFormule petit d\00E9jeuner sucr\00E9 ou sal\00E9 avec jus fait maison.\\nBelle vue mer","Descriptif du plan d''acc\00E8s":"A partir de la route nationale prendre la direction de Manapany-Les-Bains, continuer vers le bassin, le restaurant se trouve sur la gauche au num\00E9ro 127","Jours et horaires d''ouverture":"Mardi , Mercredi , Jeudi , Vendredi , Samedi","Labels":"","Date de cr\00E9ation - Etablissement":"16/3/2023","Date de fermeture":"","Fournisseur - Nom":"Mr Cl\00E9ment BARNET","Fournisseur - SIRET":"92249362200018","Fournisseur - adresse":"Mr Cl\00E9ment BARNET: 127 Boulevard de l''Oc\00E9an, 97480 Saint-Joseph","Fournisseur - contacts":"lacaseanona@gmail.com / 0693851693","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.373940, 55.589908","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'RES', U&'La Case \00E0 Nona', '91debdd2', NULL, 'RUN', 'draft', 'active', '{"legacy_object_id":"91debdd2","source_category":"Restaurant","source_subcategory":"Restaurant","source_group_category":"Restauration","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
('old-data-berta2-all-20260501-01', 'da52a8c9', 'Berta 2.0', U&'{"id":"da52a8c9","Nom commercial":"Restaurant La Table d''Elvina","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"13 rue Martin Luther-King, 97480 Saint-Joseph - Manapany-Les-Bains","Site web":"","Groupe cat\00E9gorie":"Restauration","Nom cat\00E9gorie":"Restaurant","Nom sous cat\00E9gorie":"Restaurant","Localisations":"Milieu rural","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"Manapany-Les-Bains","Prestations sur place":"ventilateur , bar , terrasse","Prestations \00E0 proximit\00E9":"centre commercial,point de vue panoramique,p\00EAche,sites touristiques,Bassin de Manapany,arr\00EAt bus,transports en commun","Mode de paiement":"Ch\00E8que,Esp\00E8ces,Carte Bancaire,Tickets restaurant","Langues":"fran\00E7ais,cr\00E9ole,anglais,allemand","Fixe":"0262 37 40 62","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"latabledelvina@gmail.com","Capacit\00E9":"80","Classement":"","Accroche":"Un nouveau lieu de vie de rencontre de partages et de convivialit\00E9 autour d\2019une cuisine savoureuse\\nEntreprise familiale","Descriptif":"Restaurant d''une capacit\00E9 de 80 personnes, restauration sur place uniquement. \\n\\nOuverts du mardi au dimanche le midi et le soir du mardi au samedi. \\nHappy Hour tous les vendredis de 18h \00E0 19h30 avec animation DJ, bi\00E8res et cocktails \00E0 moiti\00E9 prix avec planches de tapas. \\n\\nCuisine de type r\00E9unionnaise (caris, rotis...) \\nSp\00E9cialit\00E9s : baba figue, roti pied de porc, queue de cochon gros pois, cuisine lontan (coq lontan), gu\00EApes frites, wok minute (grosses crevettes palmistes), br\00E8des, bois de songes, desserts \00E0 base de fruits \00E0 pain, et autres sp\00E9cialit\00E9s ...\\nLa carte est compos\00E9e d''une s\00E9lection de plats fixes, et de plats du jour qui changent en fonction des produits de saison \\"les suggestions du jour\\".\\nCarte de boissons avec des produits locaux, cocktails et jus frais fait maison.\\nCarte des vins s\00E9lectionn\00E9s avec soin qui viennent d''un caviste local.\\n\\nUtilisation au maximum de produits de producteurs locaux et bio si possible.\\nCuisine fra\00EEche au jour le jour fait maison.\\nLe restaurant travaille avec un boucher d''excellence pour les viandes, et propose du poisson frais tous les jours (tartares, espadons,...)","Descriptif du plan d''acc\00E8s":"Sur la route nationale en direction de Manapany-Les-Bains tourner \00E0 droite sur la rue Martin Luther King le restaurant se trouve sur la gauche au num\00E9ro 13","Jours et horaires d''ouverture":"Mardi , Mercredi , Jeudi , Vendredi , Samedi , Dimanche","Labels":"","Date de cr\00E9ation - Etablissement":"16/3/2023","Date de fermeture":"","Fournisseur - Nom":"Mr Gianni TURPIN","Fournisseur - SIRET":"88887047400010","Fournisseur - adresse":"Mr Gianni TURPIN: 5 rue Leon Dehaulme, 97480 Saint-Joseph","Fournisseur - contacts":"latabledelvina@gmail.com / 0262974062","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.374960, 55.595007","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'RES', 'Restaurant La Table d''Elvina', 'da52a8c9', NULL, 'RUN', 'draft', 'active', '{"legacy_object_id":"da52a8c9","source_category":"Restaurant","source_subcategory":"Restaurant","source_group_category":"Restauration","source_zone":"sud","source_status":""}', 'pending', 'pending', 'true'),
